import{_ as a,o as e,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"机巧人偶","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/机巧人偶.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/机巧人偶.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/机巧人偶.md"};function d(o,b,l,i,_,c){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"机巧人偶",tabindex:"-1"},[p("机巧人偶 "),r("a",{class:"header-anchor",href:"#机巧人偶","aria-label":'Permalink to "机巧人偶"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),n('<h1 id="机巧人偶-1" tabindex="-1">机巧人偶 <a class="header-anchor" href="#机巧人偶-1" aria-label="Permalink to &quot;机巧人偶&quot;">​</a></h1><p>机巧人偶<br> 为代替人类作战而研发的战斗型机巧人偶，其拥有与人类相似的面容，并可以在一定程度上摸拟人类的感情,但无需将其视为人来对待，其本身只是工具。<br> material四型<br> D+1250</p><p>姓名：（自取）<br> 外貌：可以自行定制人类的外称，也可以直接裸露其中的机关结构，性别自定义，但相应的器官并无实际功能。<br> 相貌：（根据外貌设定而定，上限为7）</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量6<br> ■敏捷6<br> ■耐力6<br> ▓▓心智属性<br> ■智力2<br> ■感知4<br> ■决心2<br> ▓▓互动属性<br> ■风度2<br> ■操控2<br> ■沉着4</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动3-反射3<br> ■求生3-强韧3<br> ■射击1<br> ■武技1</p><p>▓▓心智系<br> ■学识1<br> ■器用1<br> ■手艺3-维修3<br> ■专注3-意志3</p><p>▓▓互动系<br> ■洞察5-侦查5<br> ■隐秘1<br> ■表达1<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 20米<br> ▓先攻 10<br> ▓防御 5+1<br> ▓结构值 16<br> ▓意志力池 6<br> ▓意志 8<br> ▓反射 12+1<br> ▓强韧 12+1<br> ▓侦查 10<br> ▓敏感范围 80米<br> ▓▓▓▓攻击预设：（自设）</p><p>▓▓▓▓防御预设：<br> 基础4+1<br> 盔甲2<br> ▓▓▓▓专长：<br> 机巧之躯:机巧人偶并非血肉之躯,因此在对其进行治疗时,不使用急救以及长线治疗，而是使用手艺+维修进行代替，不对结构值生效的快速医疗也无法恢复其生命。同时机巧人偶不拥有新陈代谢，其动力来源内都所装载的核能电池，因此其不需饮用水食，也无需氧气与休息并免疫无支线级的毒素和疾病。<br> 定向研发:<br> 在定向制造时若选择的是射击下属专业，则其获得3dp增强加值同时瞄准上限加1。<br> 若选择为武技下属专业，你将获得2点高速以及3点威猛，如为肉搏专业则天生武器可造成严重伤害。<br> 机型缺陷:material四型因设计缺陷导致其密封性有限，在其被液体所包裹时（例如处于水中环境）会导致其部分功能运行异常，这会令其在进行任何检定时承受3dp的环境减值。</p><p>▓▓▓▓装备位：<br> 头部<br> 头部-面部<br> 头部-耳朵<br> 颈部<br> 颈部-护符<br> 上肢-躯干<br> 肩部-斗篷<br> 上肢-双手（特殊的，手部可以同时持有两把合理的武器，但如若无特殊情况，只能在攻击时使用其中一把）<br> 手部-手腕<br> 手部-戒指（特殊的，戒指在生效时最多可以有两枚，分别为左右手佩戴的第一枚戒指）/手套（手套一般成双佩戴，手套和戒指只有一种能同时生效）<br> 腰部<br> 下肢-躯干<br> 下肢-鞋袜</p><p>▓▓▓▓强化</p><p>能量池：</p><p>技艺与称号：</p><p>见证强化：</p><p>▓▓▓▓物品：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=a(s,[["render",d]]);export{f as __pageData,m as default};
